"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[727],{2044(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/wp-next/docs/intro","label":"Introduction","docId":"intro","unlisted":false}],"adminSidebar":[{"type":"link","href":"/wp-next/docs/admin/intro","label":"Admin Dashboard","docId":"admin/intro","unlisted":false},{"type":"category","label":"Getting Started","items":[{"type":"link","href":"/wp-next/docs/admin/getting-started/installation","label":"Installation","docId":"admin/getting-started/installation","unlisted":false},{"type":"link","href":"/wp-next/docs/admin/getting-started/configuration","label":"Configurations","docId":"admin/getting-started/configuration","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Concepts & Features","items":[{"type":"link","href":"/wp-next/docs/admin/concepts-features/hooks","label":"Hooks","docId":"admin/concepts-features/hooks","unlisted":false},{"type":"link","href":"/wp-next/docs/admin/concepts-features/default-hooks","label":"Default Hooks","docId":"admin/concepts-features/default-hooks","unlisted":false},{"type":"link","href":"/wp-next/docs/admin/concepts-features/custom-page","label":"Custom Admin Page","docId":"admin/concepts-features/custom-page","unlisted":false}],"collapsed":true,"collapsible":true}],"editorSidebar":[{"type":"link","href":"/wp-next/docs/editor/intro","label":"WP Next Editor","docId":"editor/intro","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/installation","label":"Installation","docId":"editor/installation","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/getting-started","label":"Getting Started","docId":"editor/getting-started","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/canvas","label":"Canvas","docId":"editor/canvas","unlisted":false},{"type":"category","label":"Fundamentals","items":[{"type":"link","href":"/wp-next/docs/editor/fundamentals/styles","label":"Styles (CSS)","docId":"editor/fundamentals/styles","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/fundamentals/template","label":"Templates","docId":"editor/fundamentals/template","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/fundamentals/dynamic-data","label":"Dynamic Data","docId":"editor/fundamentals/dynamic-data","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/fundamentals/custom-code","label":"Custom Code","docId":"editor/fundamentals/custom-code","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/fundamentals/animations","label":"Animations","docId":"editor/fundamentals/animations","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Nodes","items":[{"type":"link","href":"/wp-next/docs/editor/nodes/overview","label":"Overview","docId":"editor/nodes/overview","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/nodes/wrapper-node","label":"Wrapper Node","docId":"editor/nodes/wrapper-node","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/nodes/template-text-node","label":"Template Text Node","docId":"editor/nodes/template-text-node","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/nodes/data-fetching-node","label":"Data Fetching Node","docId":"editor/nodes/data-fetching-node","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/nodes/collection-node","label":"Collection & Pagination","docId":"editor/nodes/collection-node","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/nodes/widget-node","label":"Widget Node","docId":"editor/nodes/widget-node","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/nodes/form-node","label":"Form Node","docId":"editor/nodes/form-node","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Concepts & Features","items":[{"type":"link","href":"/wp-next/docs/editor/concepts-features/json-editor","label":"JSON Editor","docId":"editor/concepts-features/json-editor","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/concepts-features/hiding-elements","label":"Hiding Elements","docId":"editor/concepts-features/hiding-elements","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/concepts-features/error-home-pages","label":"Error & Home Pages","docId":"editor/concepts-features/error-home-pages","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/concepts-features/configuration","label":"Configuration","docId":"editor/concepts-features/configuration","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/concepts-features/css-variables","label":"CSS Variables","docId":"editor/concepts-features/css-variables","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/concepts-features/animation-examples","label":"Animation Examples","docId":"editor/concepts-features/animation-examples","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/concepts-features/tailwind","label":"Using Tailwind","docId":"editor/concepts-features/tailwind","unlisted":false},{"type":"link","href":"/wp-next/docs/editor/concepts-features/using-ai","label":"Using AI","docId":"editor/concepts-features/using-ai","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"admin/concepts-features/custom-page":{"id":"admin/concepts-features/custom-page","title":"Custom Admin Page","description":"This guide shows how to register a custom sidebar menu item and render a custom React page inside the WP\u2011Next Admin Dashboard. It includes:","sidebar":"adminSidebar"},"admin/concepts-features/default-hooks":{"id":"admin/concepts-features/default-hooks","title":"Default Hooks","description":"When the WP-Next Admin Dashboard is initialized, a set of default hooks are created under the _wp/hooks folder.","sidebar":"adminSidebar"},"admin/concepts-features/hooks":{"id":"admin/concepts-features/hooks","title":"Hooks","description":"WP-Next supports Hooks as part of the features provided by WP-Node. These hooks work in a similar way to WordPress Hooks.","sidebar":"adminSidebar"},"admin/getting-started/configuration":{"id":"admin/getting-started/configuration","title":"Configurations","description":"WP-Next Admin Dashboard provides multiple configuration options to customize your setup.","sidebar":"adminSidebar"},"admin/getting-started/installation":{"id":"admin/getting-started/installation","title":"Installation","description":"Prerequisites","sidebar":"adminSidebar"},"admin/intro":{"id":"admin/intro","title":"Admin Dashboard","description":"WP-Next Admin Dashboard is a headless CMS that replaces the traditional WordPress admin UI. Built with React, Next.js, and Material UI, it reads and writes directly to the WordPress database \u2014 no PHP layer required.","sidebar":"adminSidebar"},"editor/canvas":{"id":"editor/canvas","title":"Canvas","description":"The canvas is the main editing environment in WP Next Editor. It is divided into four areas: the main editing area, the left navigation panel, the right navigation panel, and toolbars in the header and footer.","sidebar":"editorSidebar"},"editor/concepts-features/animation-examples":{"id":"editor/concepts-features/animation-examples","title":"Animation Examples","description":"The following examples demonstrate what the editor\'s animation system can produce using custom keyframes. Each example is a self-contained Lexical JSON template \u2014 paste it into the JSON Editor to load it directly into your template and see how it works.","sidebar":"editorSidebar"},"editor/concepts-features/configuration":{"id":"editor/concepts-features/configuration","title":"Configuration","description":"WP Next Editor is built on top of WP Node and WP Next Admin, so its configuration inherits from both packages.","sidebar":"editorSidebar"},"editor/concepts-features/css-variables":{"id":"editor/concepts-features/css-variables","title":"CSS Variables","description":"CSS Variables let you define named, typed CSS custom properties and assign them to node styles across your template. Instead of hardcoding a value like 500px into a node\'s width, you bind a variable \u2014 then change the width in one place and every node that references it updates automatically.","sidebar":"editorSidebar"},"editor/concepts-features/error-home-pages":{"id":"editor/concepts-features/error-home-pages","title":"Error & Home Pages","description":"Error and home pages are reserved templates \u2014 they use fixed, system-defined slugs rather than slugs provided by the user, so they behave differently from regular page templates.","sidebar":"editorSidebar"},"editor/concepts-features/hiding-elements":{"id":"editor/concepts-features/hiding-elements","title":"Hiding Elements","description":"The editor provides three independent hide controls that let you temporarily suppress parts of a node\'s visual output while editing. All three are editor-only \u2014 they are stored as ephemeral client-side state and never written to the template JSON or the database. Nothing you toggle here affects the published page.","sidebar":"editorSidebar"},"editor/concepts-features/json-editor":{"id":"editor/concepts-features/json-editor","title":"JSON Editor","description":"The JSON Editor gives you direct read/write access to the Lexical JSON that backs the current template. It opens as a modal with a full Monaco editor (the same editor used in VS Code), complete with syntax highlighting, auto-formatting, and inline error markers.","sidebar":"editorSidebar"},"editor/concepts-features/tailwind":{"id":"editor/concepts-features/tailwind","title":"Using Tailwind","description":"The editor\'s Additional Class Names field accepts any CSS class name, which makes it straightforward to use Tailwind CSS utility classes. The most practical way to load Tailwind without a build step is via the Play CDN.","sidebar":"editorSidebar"},"editor/concepts-features/using-ai":{"id":"editor/concepts-features/using-ai","title":"Using AI","description":"Because all templates in WP Next Editor are stored as structured Lexical JSON, AI agents can read, write, and transform them directly. A template that would take hours to build manually can often be scaffolded in seconds.","sidebar":"editorSidebar"},"editor/fundamentals/animations":{"id":"editor/fundamentals/animations","title":"Animations","description":"The Animations system lets you attach CSS-based animation rules to any node. Rules are triggered by user interactions (hover, click, scroll, etc.) and use either preset keyframes or your own custom-defined ones.","sidebar":"editorSidebar"},"editor/fundamentals/custom-code":{"id":"editor/fundamentals/custom-code","title":"Custom Code","description":"Custom Code lets you inject HTML, CSS, or JavaScript into a template\'s ` or just before the closing ` tag. Use it to load external frameworks (Tailwind, GTAG, analytics scripts, icon libraries), add global styles, or include any inline script the page needs.","sidebar":"editorSidebar"},"editor/fundamentals/dynamic-data":{"id":"editor/fundamentals/dynamic-data","title":"Working with Dynamic Data","description":"Dynamic data connects template elements to live WordPress database content \u2014 posts, pages, users, taxonomies, options, and more. Instead of hardcoding text and values, you define what data to fetch, then bind specific fields to elements so the page renders with real content at request time.","sidebar":"editorSidebar"},"editor/fundamentals/styles":{"id":"editor/fundamentals/styles","title":"Styles (CSS)","description":"The Styles tab in the right panel is the primary way to apply CSS to any node or element. Each property you set is stored per-device (breakpoint) and per-state (e.g. hover), and the editor generates the corresponding CSS media queries and pseudo-class selectors automatically.","sidebar":"editorSidebar"},"editor/fundamentals/template":{"id":"editor/fundamentals/template","title":"Templates","description":"In WP Next Editor, a template is a Lexical-based document stored as JSON. Every element on the canvas \u2014 its content, layout, styles, animations, and data bindings \u2014 is serialized into the template\'s JSON representation and stored in the WordPress database.","sidebar":"editorSidebar"},"editor/getting-started":{"id":"editor/getting-started","title":"Getting Started","description":"This guide walks you through creating your first template and publishing it as a public page.","sidebar":"editorSidebar"},"editor/installation":{"id":"editor/installation","title":"Installation","description":"The Editor installation process is the same as the Admin Dashboard, except for the CLI command used to initialize the project.","sidebar":"editorSidebar"},"editor/intro":{"id":"editor/intro","title":"WP Next Editor","description":"WP Next Editor is a visual, drag-and-drop page editor for building public-facing pages directly connected to your WordPress database. Pages are stored as structured Lexical JSON in the WP database \u2014 making them version-controllable, programmatically manipulable, and AI-ready.","sidebar":"editorSidebar"},"editor/nodes/collection-node":{"id":"editor/nodes/collection-node","title":"Collection & Pagination","description":"The Collection Node renders a list of items from array data \u2014 for example, a list of posts fetched by a PostsDataFetchingNode. It is the primary tool for building repeating layouts like post grids, user lists, and search results.","sidebar":"editorSidebar"},"editor/nodes/data-fetching-node":{"id":"editor/nodes/data-fetching-node","title":"Data Fetching Node","description":"The Data Fetching Node is a base node that fetches data from the WordPress database via a Next.js server action. It is not used directly in templates \u2014 other, more specific nodes extend it and implement the required fetch() method.","sidebar":"editorSidebar"},"editor/nodes/form-node":{"id":"editor/nodes/form-node","title":"Form Node","description":"The Form Node is experimental. Its API and configuration may change in future releases.","sidebar":"editorSidebar"},"editor/nodes/overview":{"id":"editor/nodes/overview","title":"Nodes Overview","description":"Every template in the WP Next Editor is a tree of Lexical nodes, managed by the Lexical editor state. The entire template serializes to JSON \u2014 making it version-controllable and AI-manipulable \u2014 and Lexical renders it to HTML as the final output.","sidebar":"editorSidebar"},"editor/nodes/template-text-node":{"id":"editor/nodes/template-text-node","title":"Template Text Node","description":"The Template Text Node is the base text node in the WP Next Editor. It extends Lexical\'s built-in TextNode with one key addition: support for ${} syntax that resolves dynamic data at render time.","sidebar":"editorSidebar"},"editor/nodes/widget-node":{"id":"editor/nodes/widget-node","title":"Widget Node","description":"The Widget Node renders another template (a \\"widget template\\") as an embedded sub-template inside the current template. This is the primary mechanism for building reusable components \u2014 headers, footers, sidebars, and any other layout piece that is shared across multiple pages.","sidebar":"editorSidebar"},"editor/nodes/wrapper-node":{"id":"editor/nodes/wrapper-node","title":"Wrapper Node","description":"The Wrapper Node is the most fundamental building block in the WP Next Editor. It extends WPElementNode, which means it can contain other nodes \u2014 other Wrapper Nodes, Template Text Nodes, Data Fetching Nodes, and so on.","sidebar":"editorSidebar"},"intro":{"id":"intro","title":"Introduction","description":"WP-Next is a Next.js/TypeScript platform that implements a visual page editor and headless CMS using the WordPress database \u2014 entirely in TypeScript, with no PHP required. It reads and writes directly to the WordPress database via wp-node and ships two products:","sidebar":"tutorialSidebar"}}}}')}}]);